"use client";

import React, { useState } from 'react'; // 1. Pridali sme useState
import styles from './page.module.css';

export default function LoginPage() {
  // 2. Vytvoríme "pamäť" pre email a heslo
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  // 3. Funkcia, ktorá sa spustí pri kliknutí na tlačidlo
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      const response = await fetch('http://localhost:4000/auth/login', { // 4000 je bežný port pre NestJS
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ email, password }),
      });

      const result = await response.json();
      alert(result.message); // Backend nám odpovie, či to prešlo
    } catch (error) {
      console.error('Chyba pripojenia:', error);
      alert('Backend nie je spustený!');
    }
  };

  return (
    <div className={styles['login-container']}> 
      <h1>Prihlásenie</h1>
      <form className={styles['login-form']} onSubmit={handleSubmit}>
        <input 
          className={styles['login-input']} 
          type="email" 
          placeholder="Email" 
          value={email}
          onChange={(e) => setEmail(e.target.value)} // Zapíšeme zmenu do pamäte
          required
        />
        <input 
          className={styles['login-input']} 
          type="password" 
          placeholder="Heslo" 
          value={password}
          onChange={(e) => setPassword(e.target.value)} // Zapíšeme zmenu do pamäte
          required
        />
        <button className={styles['login-button']} type="submit">
          Vstúpiť
        </button>
      </form>
    </div>
  );
}
